   857	void Vector::DebugTransformToDictionary(Vector &vector, idx_t count) {
   858		if (vector.GetVectorType() != VectorType::FLAT_VECTOR) {
   859			// only supported for flat vectors currently
   860			return;
   861		}
   862		// convert vector to dictionary vector
   863		// first create an inverted vector of twice the size with NULL values every other value
   864		// i.e. [1, 2, 3] is converted into [NULL, 3, NULL, 2, NULL, 1]
   865		idx_t verify_count = count * 2;
   866		SelectionVector inverted_sel(verify_count);
   867		idx_t offset = 0;
   868		for (idx_t i = 0; i < count; i++) {
   869			idx_t current_index = count - i - 1;
   870			inverted_sel.set_index(offset++, current_index);
   871			inverted_sel.set_index(offset++, current_index);
   872		}
   873		auto reusable_dict = DictionaryVector::CreateReusableDictionary(vector.type, verify_count);
   874		auto &inverted_vector = reusable_dict->data;
   875		inverted_vector.Slice(vector, inverted_sel, verify_count);
   876		inverted_vector.Flatten(verify_count);
   877		// now insert the NULL values at every other position
   878		for (idx_t i = 0; i < count; i++) {
   879			FlatVector::SetNull(inverted_vector, i * 2, true);
   880		}
   881		// construct the selection vector pointing towards the original values
   882		// we start at the back, (verify_count - 1) and move backwards
   883		SelectionVector original_sel(count);
   884		offset = 0;
   885		for (idx_t i = 0; i < count; i++) {
   886			original_sel.set_index(offset++, verify_count - 1 - i * 2);
   887		}
   888		// now slice the inverted vector with the inverted selection vector
   889		if (vector.GetType().InternalType() == PhysicalType::STRUCT) {
   890			// Reusable dictionary API does not work for STRUCT
   891			vector.Dictionary(inverted_vector, verify_count, original_sel, count);
   892		} else {
   893			vector.Dictionary(reusable_dict, original_sel, count);
   894		}
   895		vector.Verify(count);
   896	}
