   167	static bool ArrayToListCast(Vector &source, Vector &result, idx_t count, CastParameters &parameters) {
   168		auto &cast_data = parameters.cast_data->Cast<ArrayBoundCastData>();
   169	
   170		// FIXME: dont flatten
   171		source.Flatten(count);
   172	
   173		auto array_size = ArrayType::GetSize(source.GetType());
   174		auto child_count = count * array_size;
